class MinStack {
    constructor() {
        this.st = [];
    }
    push(value) {
        if (this.st.length === 0) {
            this.st.push([value, value]);
            return;
        }
        const mini = Math.min(this.getMin(), value);
        this.st.push([value, mini]);
    }
    pop() {
        this.st.pop();
    }
    top() {
        return this.st[this.st.length - 1][0];
    }
    getMin() {
        return this.st[this.st.length - 1][1];
    }
